{"parameters":"z.object({ maxBlocks: z.number().int().min(1).max(10).default(2).describe("Maximum number of blocks to place for cover."), targetHostileId: z.union([z.number(), z.string()]).optional().describe("Specific hostile entity ID to hide from. If omitted, the nearest hostile is used."), preferredBlockName: z.string().default("oak_planks").describe("The block type to use for cover.") })","executionArgs":{"maxBlocks":2,"preferredBlockName":"oak_planks"},"code":"const pollMs = 100;
const hostileNames = new Set(['zombie', 'skeleton', 'husk', 'drowned', 'stray', 'spider', 'creeper', 'baby_zombie', 'pillager', 'ravager']);

if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is dead or missing.';
}

const findTarget = function () {
  if (args.targetHostileId) {
    return bot.entities[args.targetHostileId];
  }
  let closest = null;
  let minDist = 20;
  for (const id in bot.entities) {
    const e = bot.entities[id];
    if (e && e.isValid && (e.kind === 'Hostile mobs' || hostileNames.has(e.name))) {
      const dist = bot.entity.position.distanceTo(e.position);
      if (dist < minDist) {
        minDist = dist;
        closest = e;
      }
    }
  }
  return closest;
};

const getBlockFromInventory = function () {
  const name = args.preferredBlockName.toLowerCase().replace(/\\s+/g, '_');
  return bot.inventory.items().find(function (item) {
    const iName = item.name.toLowerCase();
    return iName.includes(name) || iName.includes('planks') || iName.includes('cobblestone') || iName.includes('dirt');
  });
};

const target = findTarget();
if (!target) {
  return '<NO TARGET>: No nearby threat found to provide cover from.';
}

const blockToUse = getBlockFromInventory();
if (!blockToUse) {
  return '<NO ITEM>: No suitable building blocks found in inventory.';
}

startBackgroundSkill(bot, 'place_cover', async function (token) {
  try {
    for (let i = 0; i < args.maxBlocks; i++) {
      if (!canContinueBotAction(bot, token)) return;

      const currentTarget = findTarget();
      if (!currentTarget) return;

      const botPos = bot.entity.position.clone();
      const threatPos = currentTarget.position.clone();
      const dir = threatPos.minus(botPos).normalize();

      // Place block about 1.5 blocks away from bot in direction of threat
      const blockPos = botPos.plus(dir.scaled(1.5)).floored();
      // Adjust Y to floor if needed or stack if it's the second block
      blockPos.y = Math.floor(botPos.y) + i;

      const existingBlock = bot.blockAt(blockPos);
      if (!existingBlock || existingBlock.name !== 'air') {
        if (i === 0) blockPos.y += 1; // Try one higher if floor is occupied
        else continue;
      }

      const referenceBlock = bot.blockAt(blockPos.offset(0, -1, 0));
      if (!referenceBlock || referenceBlock.name === 'air') {
        // Cannot place in mid-air without a neighbor; in this survival context we look for the floor
        continue;
      }

      const item = getBlockFromInventory();
      if (!item) return;

      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      await bot.equip(item, 'hand');

      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      await bot.lookAt(blockPos.offset(0.5, 0.5, 0.5), true);

      try {
        if (!await waitUntilWorldActive(bot, token, pollMs)) return;
        await bot.placeBlock(referenceBlock, new Vec3(0, 1, 0));
      } catch (err) {
        // Placement failed (e.g. obstructed)
      }

      await waitForActiveMs(bot, token, 100, pollMs);
    }
  } finally {
    // No specific cleanup needed for block placement
  }
});

return '<STARTED>: Placing up to ' + args.maxBlocks + ' blocks of cover against ' + target.name + '.';"}
